/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    ETGIntegrationInvoice        arAPRef;
    DialogField                  dialogARAPRef;
    DialogField                  dialogTransType;
    ;

    dialog = new dialog("Integration unprocessed order validation");
    dialogARAPRef       = dialog.addField(extendedTypeStr(ETGIntegrationInvoice), "Invoice number");
    dialog.run();

    if(!dialogARAPRef.value())
    {
        throw error("Invoice number should be fill");
    }
    else if (dialog.run())
    {
        this.create(dialogARAPRef.value());
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create(ETGIntegrationInvoice _arAPRef)
{
    ETG_ARAP_MSGHEADER header;
    ETG_GeneralJournalIntegration  generalJournalIntegration = new ETG_GeneralJournalIntegration();

    select * from header where header.ETGARAPREF == _arAPRef;
    // && header.ETGIntegrationsStatus == ETGIntegrationStatus::Unprocessed;

    if(header.ETGDocuType == "INV")
    {
        generalJournalIntegration.postInvoice(header.ETGARAPREF);
    }
    else if(header.ETGDocuType == "VCH")
    {
        generalJournalIntegration.PostVCH(header.ETGARAPREF);
    }
    else if(header.ETGDocuType == "ARCN")
    {
        generalJournalIntegration.PostARCN(header.ETGARAPREF);
    }
    else if(header.ETGDocuType == "ARDN")
    {
        generalJournalIntegration.PostARDN(header.ETGARAPREF);
    }
    else if(header.ETGDocuType == "APDN")
    {
        generalJournalIntegration.PostAPDN(header.ETGARAPREF);
    }
    else if(header.ETGDocuType == "APCN")
    {
        generalJournalIntegration.PostAPCN(header.ETGARAPREF);
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGIntegrationUnprocessedOrdersValidation validation;

    validation = new ETGIntegrationUnprocessedOrdersValidation();
    validation.run();
}
